56: class ExtProcLoggingInfo : public Envoy::StreamInfo::FilterState::Object {
57: public:
58:   explicit ExtProcLoggingInfo(const Envoy::ProtobufWkt::Struct& filter_metadata)
59:       : filter_metadata_(filter_metadata) {}
60: 
61:   // gRPC call stats for headers and trailers.
62:   struct GrpcCall {
63:     GrpcCall(const std::chrono::microseconds latency, const Grpc::Status::GrpcStatus call_status)
64:         : latency_(latency), call_status_(call_status) {}
65:     const std::chrono::microseconds latency_;
66:     const Grpc::Status::GrpcStatus call_status_;
67:   };
68: 
69:   // gRPC call stats for body.
70:   struct GrpcCallBody {
71:     GrpcCallBody(const uint32_t call_count, const Grpc::Status::GrpcStatus call_status,
72:                  const std::chrono::microseconds total_latency,
73:                  const std::chrono::microseconds max_latency,
74:                  const std::chrono::microseconds min_latency)
75:         : call_count_(call_count), last_call_status_(call_status), total_latency_(total_latency),
76:           max_latency_(max_latency), min_latency_(min_latency) {}
77:     uint32_t call_count_;
78:     Grpc::Status::GrpcStatus last_call_status_;
79:     std::chrono::microseconds total_latency_;
80:     std::chrono::microseconds max_latency_;
81:     std::chrono::microseconds min_latency_;
82:   };
83: 
84:   struct GrpcCallStats {
85:     std::unique_ptr<GrpcCall> header_stats_;
86:     std::unique_ptr<GrpcCall> trailer_stats_;
87:     std::unique_ptr<GrpcCallBody> body_stats_;
88:   };
89: 
90:   using GrpcCalls = struct GrpcCallStats;
91: 
92:   void recordGrpcCall(std::chrono::microseconds latency, Grpc::Status::GrpcStatus call_status,
93:                       ProcessorState::CallbackState callback_state,
94:                       envoy::config::core::v3::TrafficDirection traffic_direction);
95:   void setBytesSent(uint64_t bytes_sent) { bytes_sent_ = bytes_sent; }
96:   void setBytesReceived(uint64_t bytes_received) { bytes_received_ = bytes_received; }
97:   void setClusterInfo(absl::optional<Upstream::ClusterInfoConstSharedPtr> cluster_info) {
98:     if (cluster_info) {
99:       cluster_info_ = cluster_info.value();
100:     }
101:   }
102:   void setUpstreamHost(absl::optional<Upstream::HostDescriptionConstSharedPtr> upstream_host) {
103:     if (upstream_host) {
104:       upstream_host_ = upstream_host.value();
105:     }
106:   }
107: 
108:   uint64_t bytesSent() const { return bytes_sent_; }
109:   uint64_t bytesReceived() const { return bytes_received_; }
110:   Upstream::ClusterInfoConstSharedPtr clusterInfo() const { return cluster_info_; }
111:   Upstream::HostDescriptionConstSharedPtr upstreamHost() const { return upstream_host_; }
112:   const GrpcCalls& grpcCalls(envoy::config::core::v3::TrafficDirection traffic_direction) const;
113:   const Envoy::ProtobufWkt::Struct& filterMetadata() const { return filter_metadata_; }
114: 
115: private:
116:   GrpcCalls& grpcCalls(envoy::config::core::v3::TrafficDirection traffic_direction);
117:   GrpcCalls decoding_processor_grpc_calls_;
118:   GrpcCalls encoding_processor_grpc_calls_;
119:   const Envoy::ProtobufWkt::Struct filter_metadata_;
120:   // The following stats are populated for ext_proc filters using Envoy gRPC only.
121:   // The bytes sent and received are for the entire stream.
122:   uint64_t bytes_sent_{0}, bytes_received_{0};
123:   Upstream::ClusterInfoConstSharedPtr cluster_info_;
124:   Upstream::HostDescriptionConstSharedPtr upstream_host_;
125: };
