148: class FilterConfig {
149: public:
150:   FilterConfig(const envoy::extensions::filters::http::ext_proc::v3::ExternalProcessor& config,
151:                const std::chrono::milliseconds message_timeout,
152:                const uint32_t max_message_timeout_ms, Stats::Scope& scope,
153:                const std::string& stats_prefix, bool is_upstream,
154:                Extensions::Filters::Common::Expr::BuilderInstanceSharedPtr builder,
155:                Server::Configuration::CommonFactoryContext& context)
156:       : failure_mode_allow_(config.failure_mode_allow()),
157:         disable_clear_route_cache_(config.disable_clear_route_cache()),
158:         message_timeout_(message_timeout), max_message_timeout_ms_(max_message_timeout_ms),
159:         stats_(generateStats(stats_prefix, config.stat_prefix(), scope)),
160:         processing_mode_(config.processing_mode()),
161:         mutation_checker_(config.mutation_rules(), context.regexEngine()),
162:         filter_metadata_(config.filter_metadata()),
163:         allow_mode_override_(config.allow_mode_override()),
164:         disable_immediate_response_(config.disable_immediate_response()),
165:         allowed_headers_(initHeaderMatchers(config.forward_rules().allowed_headers(), context)),
166:         disallowed_headers_(
167:             initHeaderMatchers(config.forward_rules().disallowed_headers(), context)),
168:         is_upstream_(is_upstream),
169:         untyped_forwarding_namespaces_(
170:             config.metadata_options().forwarding_namespaces().untyped().begin(),
171:             config.metadata_options().forwarding_namespaces().untyped().end()),
172:         typed_forwarding_namespaces_(
173:             config.metadata_options().forwarding_namespaces().typed().begin(),
174:             config.metadata_options().forwarding_namespaces().typed().end()),
175:         untyped_receiving_namespaces_(
176:             config.metadata_options().receiving_namespaces().untyped().begin(),
177:             config.metadata_options().receiving_namespaces().untyped().end()),
178:         expression_manager_(builder, context.localInfo(), config.request_attributes(),
179:                             config.response_attributes()),
180:         immediate_mutation_checker_(context.regexEngine()) {}
181: 
182:   bool failureModeAllow() const { return failure_mode_allow_; }
183: 
184:   const std::chrono::milliseconds& messageTimeout() const { return message_timeout_; }
185: 
186:   uint32_t maxMessageTimeout() const { return max_message_timeout_ms_; }
187: 
188:   const ExtProcFilterStats& stats() const { return stats_; }
189: 
190:   const envoy::extensions::filters::http::ext_proc::v3::ProcessingMode& processingMode() const {
191:     return processing_mode_;
192:   }
193: 
194:   bool allowModeOverride() const { return allow_mode_override_; }
195:   bool disableImmediateResponse() const { return disable_immediate_response_; }
196: 
197:   const Filters::Common::MutationRules::Checker& mutationChecker() const {
198:     return mutation_checker_;
199:   }
200: 
201:   bool disableClearRouteCache() const { return disable_clear_route_cache_; }
202: 
203:   const std::vector<Matchers::StringMatcherPtr>& allowedHeaders() const { return allowed_headers_; }
204:   const std::vector<Matchers::StringMatcherPtr>& disallowedHeaders() const {
205:     return disallowed_headers_;
206:   }
207: 
208:   const ProtobufWkt::Struct& filterMetadata() const { return filter_metadata_; }
209: 
210:   const ExpressionManager& expressionManager() const { return expression_manager_; }
211: 
212:   bool isUpstream() const { return is_upstream_; }
213: 
214:   const std::vector<std::string>& untypedForwardingMetadataNamespaces() const {
215:     return untyped_forwarding_namespaces_;
216:   }
217: 
218:   const std::vector<std::string>& typedForwardingMetadataNamespaces() const {
219:     return typed_forwarding_namespaces_;
220:   }
221: 
222:   const std::vector<std::string>& untypedReceivingMetadataNamespaces() const {
223:     return untyped_receiving_namespaces_;
224:   }
225: 
226:   const ImmediateMutationChecker& immediateMutationChecker() const {
227:     return immediate_mutation_checker_;
228:   }
229: 
230: private:
231:   ExtProcFilterStats generateStats(const std::string& prefix,
232:                                    const std::string& filter_stats_prefix, Stats::Scope& scope) {
233:     const std::string final_prefix = absl::StrCat(prefix, "ext_proc.", filter_stats_prefix);
234:     return {ALL_EXT_PROC_FILTER_STATS(POOL_COUNTER_PREFIX(scope, final_prefix))};
235:   }
236:   const bool failure_mode_allow_;
237:   const bool disable_clear_route_cache_;
238:   const std::chrono::milliseconds message_timeout_;
239:   const uint32_t max_message_timeout_ms_;
240: 
241:   ExtProcFilterStats stats_;
242:   const envoy::extensions::filters::http::ext_proc::v3::ProcessingMode processing_mode_;
243:   const Filters::Common::MutationRules::Checker mutation_checker_;
244:   const ProtobufWkt::Struct filter_metadata_;
245:   // If set to true, allow the processing mode to be modified by the ext_proc response.
246:   const bool allow_mode_override_;
247:   // If set to true, disable the immediate response from the ext_proc server, which means
248:   // closing the stream to the ext_proc server, and no more external processing.
249:   const bool disable_immediate_response_;
250:   // Empty allowed_header_ means allow all.
251:   const std::vector<Matchers::StringMatcherPtr> allowed_headers_;
252:   // Empty disallowed_header_ means disallow nothing, i.e, allow all.
253:   const std::vector<Matchers::StringMatcherPtr> disallowed_headers_;
254:   // is_upstream_ is true if ext_proc filter is in the upstream filter chain.
255:   const bool is_upstream_;
256:   const std::vector<std::string> untyped_forwarding_namespaces_;
257:   const std::vector<std::string> typed_forwarding_namespaces_;
258:   const std::vector<std::string> untyped_receiving_namespaces_;
259:   const ExpressionManager expression_manager_;
260: 
261:   const ImmediateMutationChecker immediate_mutation_checker_;
262: };
